{
  "name": "Oracle AI - I Ching",
  "description": "A modern, AI-enhanced I Ching (Book of Changes) application. Cast hexagrams using digital coins and receive profound interpretations powered by Gemini."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum LineType {
  YoungYin = 8,  // - - (Static)
  YoungYang = 7, // --- (Static)
  OldYin = 6,    // -x- (Changing to Yang)
  OldYang = 9,   // -o- (Changing to Yin)
}

export interface HexagramData {
  number: number;
  name: string;
  character: string;
  pinyin: string;
  english: string;
  description: string;
}

export interface CastLine {
  value: number; // 6, 7, 8, or 9
  type: LineType;
}

export interface ReadingResult {
  lines: CastLine[];
  originalHexagram: HexagramData;
  transformedHexagram?: HexagramData; // If there are changing lines
  timestamp: number;
  question: string;
  aiInterpretation?: string;
}

export type CoinSide = 2 | 3; // 2 = Tails (Yin), 3 = Heads (Yang)

import { CastLine, HexagramData, LineType } from '../types';
import { HEXAGRAMS } from '../constants';

export const tossCoins = (): CastLine => {
  // 3 coins. Each has a value of 2 (Tails/Yin) or 3 (Heads/Yang).
  // Probabilities:
  // 3 Heads (3+3+3=9) -> Old Yang (1/8)
  // 3 Tails (2+2+2=6) -> Old Yin (1/8)
  // 1 Head 2 Tails (3+2+2=7) -> Young Yang (3/8)
  // 2 Heads 1 Tail (3+3+2=8) -> Young Yin (3/8)

  const coin1 = Math.random() < 0.5 ? 2 : 3;
  const coin2 = Math.random() < 0.5 ? 2 : 3;
  const coin3 = Math.random() < 0.5 ? 2 : 3;

  const sum = coin1 + coin2 + coin3;

  return {
    value: sum,
    type: sum as LineType,
  };
};

export const getHexagramFromLines = (lines: CastLine[]): { original: HexagramData, transformed?: HexagramData } => {
  // Construct binary string from bottom (lines[0]) to top (lines[5])

  // Original: 6(Old Yin) -> 0, 7(Young Yang) -> 1, 8(Young Yin) -> 0, 9(Old Yang) -> 1
  // Basically Yang is odd, Yin is even
  const originalBinary = lines.map(l => (l.value % 2 === 1 ? '1' : '0')).join('');

  const original = HEXAGRAMS[originalBinary];

  // Transformed: Old lines flip. Young lines stay.
  // 6 (Old Yin 0) -> becomes 1
  // 9 (Old Yang 1) -> becomes 0
  const hasMovingLines = lines.some(l => l.value === 6 || l.value === 9);

  let transformed: HexagramData | undefined = undefined;

  if (hasMovingLines) {
    const transformedBinary = lines.map(l => {
      if (l.value === 6) return '1'; // Old Yin (0) becomes Yang (1)
      if (l.value === 9) return '0'; // Old Yang (1) becomes Yin (0)
      return (l.value % 2 === 1 ? '1' : '0'); // Statics stay same
    }).join('');

    transformed = HEXAGRAMS[transformedBinary];
  }

  return { original, transformed };
};

export const getChangingLinesIndices = (lines: CastLine[]): number[] => {
    return lines
        .map((l, idx) => (l.value === 6 || l.value === 9 ? idx + 1 : 0))
        .filter(idx => idx !== 0);
};

import { GoogleGenAI } from "@google/genai";
import { CastLine, HexagramData } from '../types';
import { getChangingLinesIndices } from '../utils/ichingLogic';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getInterpretation = async (
  question: string,
  lines: CastLine[],
  original: HexagramData,
  transformed?: HexagramData
): Promise<string> => {

  const changingLines = getChangingLinesIndices(lines);

  let prompt = `You are an I Ching master sage. The user has asked the following question: "${question}".\n\n`;

  prompt += `The cast resulted in Hexagram ${original.number}: ${original.name} (${original.english}).\n`;
  prompt += `Character: ${original.character}\n`;
  prompt += `Key attributes: ${original.description}\n\n`;

  if (changingLines.length > 0) {
    prompt += `There are changing lines at positions: ${changingLines.join(', ')}.\n`;
    if (transformed) {
        prompt += `The hexagram transforms into Hexagram ${transformed.number}: ${transformed.name} (${transformed.english}).\n`;
        prompt += `Transformed attributes: ${transformed.description}\n`;
    }
  } else {
    prompt += `There are no changing lines. This indicates a static situation.\n`;
  }

  prompt += `\nPlease provide a profound, wisdom-filled, yet practical interpretation for the user. Structure the response in markdown with the following sections:\n`;
  prompt += `1. **The Core Situation**: What the primary hexagram says about their question.\n`;
  if (changingLines.length > 0) {
    prompt += `2. **The Changing Lines**: Specific advice based on the moving lines (refer to them as "Line [x]").\n`;
    prompt += `3. **The Outcome**: What the transformed hexagram implies for the future evolution of the situation.\n`;
  }
  prompt += `4. **Sage's Advice**: A concise, actionable summary.\n\n`;
  prompt += `Tone: Mystical, calm, empathetic, and insightful. Avoid overly generic horoscope-style writing.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        temperature: 0.7,
      }
    });

    return response.text || "The oracle is silent at this moment. Please reflect on your question and try again.";
  } catch (error) {
    console.error("Error fetching interpretation:", error);
    return "The connection to the ethereal realm is disrupted. Please check your network and try again.";
  }
};

import React, { useEffect, useState } from 'react';

interface CoinAnimationProps {
  onTossComplete: () => void;
  isTossing: boolean;
}

const CoinAnimation: React.FC<CoinAnimationProps> = ({ onTossComplete, isTossing }) => {
  const [showResult, setShowResult] = useState(false);

  useEffect(() => {
    let timer: NodeJS.Timeout;
    if (isTossing) {
      setShowResult(false);
      // Simulate animation duration
      timer = setTimeout(() => {
        setShowResult(true);
        // Small delay to show result before callback
        setTimeout(onTossComplete, 500); 
      }, 1500);
    }
    return () => clearTimeout(timer);
  }, [isTossing, onTossComplete]);

  if (!isTossing && !showResult) return null;

  return (
    <div className="flex justify-center gap-8 my-8 perspective-500">
      {[1, 2, 3].map((i) => (
        <div key={i} className={`relative w-16 h-16 rounded-full border-4 border-amber-500 bg-amber-200 shadow-[0_0_15px_rgba(245,158,11,0.5)] flex items-center justify-center text-amber-900 font-bold text-xl ${isTossing ? 'animate-[spin_0.5s_ease-in-out_infinite]' : ''}`}>
           <span className="opacity-80">
             {/* Simple visual representation */}
             {isTossing ? '?' : ((Math.random() > 0.5) ? 'Yin' : 'Yang')}
           </span>
        </div>
      ))}
      <style>{`
        .perspective-500 { perspective: 500px; }
      `}</style>
    </div>
  );
};

export default CoinAnimation;

import React from 'react';
import { CastLine, LineType } from '../types';

interface HexagramDisplayProps {
  lines: CastLine[];
  active?: boolean; // If true, lines are animated in
  highlightMoving?: boolean;
}

const LineBar: React.FC<{ type: LineType; index: number; highlightMoving?: boolean }> = ({ type, index, highlightMoving }) => {
  const isYang = type === LineType.YoungYang || type === LineType.OldYang;
  const isMoving = type === LineType.OldYin || type === LineType.OldYang;

  // Determine colors
  const baseColor = "bg-amber-100";
  const movingColor = highlightMoving && isMoving ? "bg-red-400" : baseColor;

  return (
    <div className="w-full max-w-[200px] h-4 sm:h-6 my-1 sm:my-2 flex justify-between items-center relative transition-all duration-500 ease-out transform translate-y-0 opacity-100">

      {/* Yang Line: Solid bar */}
      {isYang && (
        <div className={`w-full h-full ${movingColor} shadow-[0_0_10px_rgba(255,255,255,0.2)] rounded-sm`}></div>
      )}

      {/* Yin Line: Split bar */}
      {!isYang && (
        <>
          <div className={`w-[45%] h-full ${movingColor} shadow-[0_0_10px_rgba(255,255,255,0.2)] rounded-sm`}></div>
          <div className={`w-[45%] h-full ${movingColor} shadow-[0_0_10px_rgba(255,255,255,0.2)] rounded-sm`}></div>
        </>
      )}

      {/* Changing Marker (Circle or X) */}
      {isMoving && highlightMoving && (
        <div className="absolute left-1/2 top-1/2 transform -translate-x-1/2 -translate-y-1/2 text-slate-900 font-bold text-xs sm:text-sm pointer-events-none">
          {type === LineType.OldYang ? 'O' : 'X'}
        </div>
      )}
    </div>
  );
};

const HexagramDisplay: React.FC<HexagramDisplayProps> = ({ lines, highlightMoving = true }) => {
  // We display lines from Top (index 5) to Bottom (index 0) visually, 
  // but standard casting order is bottom-up. 
  // Standard display: Line 6 is at the top.

  const reversedLines = [...lines].reverse(); // Copy and reverse for visual stacking (6 on top)

  return (
    <div className="flex flex-col items-center p-4 bg-slate-800/50 rounded-lg border border-slate-700 shadow-xl backdrop-blur-sm min-w-[250px]">
      {reversedLines.map((line, idx) => {
        // reversedLines[0] is actually line 6 (index 5 of original)
        // reversedLines[5] is actually line 1 (index 0 of original)
        const originalIndex = lines.length - 1 - idx;
        return (
          <LineBar 
            key={`line-${originalIndex}`} 
            type={line.type} 
            index={originalIndex} 
            highlightMoving={highlightMoving} 
          />
        );
      })}
      {lines.length === 0 && (
         <div className="h-48 flex items-center justify-center text-slate-500 italic">
           No lines cast yet
         </div>
      )}
    </div>
  );
};

export default HexagramDisplay;

import React from 'react';
import { ReadingResult } from '../types';

interface HistorySidebarProps {
  history: ReadingResult[];
  onSelect: (reading: ReadingResult) => void;
  isOpen: boolean;
  onClose: () => void;
}

const HistorySidebar: React.FC<HistorySidebarProps> = ({ history, onSelect, isOpen, onClose }) => {
  return (
    <>
      {/* Backdrop */}
      {isOpen && (
        <div 
          className="fixed inset-0 bg-black/60 z-40 lg:hidden" 
          onClick={onClose}
        />
      )}

      <div className={`fixed top-0 right-0 h-full w-80 bg-slate-900 border-l border-slate-700 transform transition-transform duration-300 z-50 overflow-y-auto ${isOpen ? 'translate-x-0' : 'translate-x-full'}`}>
        <div className="p-4 border-b border-slate-700 flex justify-between items-center">
          <h2 className="text-xl font-serif text-amber-500">History</h2>
          <button onClick={onClose} className="text-slate-400 hover:text-white">✕</button>
        </div>

        <div className="p-4 space-y-4">
          {history.length === 0 ? (
            <p className="text-slate-500 text-center mt-10">No past readings recorded.</p>
          ) : (
            history.map((reading, idx) => (
              <div 
                key={idx} 
                onClick={() => { onSelect(reading); onClose(); }}
                className="p-3 bg-slate-800 rounded border border-slate-700 hover:border-amber-500 cursor-pointer transition-colors group"
              >
                <p className="text-xs text-slate-400 mb-1">
                  {new Date(reading.timestamp).toLocaleDateString()} • {new Date(reading.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                </p>
                <h3 className="font-serif text-amber-100 group-hover:text-amber-400 font-bold mb-1">
                  {reading.originalHexagram.number}. {reading.originalHexagram.english}
                </h3>
                <p className="text-sm text-slate-300 truncate italic">"{reading.question}"</p>
                {reading.transformedHexagram && (
                   <p className="text-xs text-slate-500 mt-1">
                     → {reading.transformedHexagram.number}. {reading.transformedHexagram.english}
                   </p>
                )}
              </div>
            ))
          )}
        </div>
      </div>
    </>
  );
};

export default HistorySidebar;

import React, { useState, useEffect, useRef } from 'react';
import { CastLine, ReadingResult } from './types';
import { tossCoins, getHexagramFromLines } from './utils/ichingLogic';
import HexagramDisplay from './components/HexagramDisplay';
import CoinAnimation from './components/CoinAnimation';
import HistorySidebar from './components/HistorySidebar';
import { getInterpretation } from './services/geminiService';
import { GoogleGenAI } from "@google/genai";

// Ensure AI client is init
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const App: React.FC = () => {
  // State
  const [question, setQuestion] = useState('');
  const [lines, setLines] = useState<CastLine[]>([]);
  const [isCasting, setIsCasting] = useState(false); // Coin spinning state
  const [stage, setStage] = useState<'input' | 'casting' | 'result'>('input');
  const [readingResult, setReadingResult] = useState<ReadingResult | null>(null);
  const [isLoadingAI, setIsLoadingAI] = useState(false);

  // History
  const [history, setHistory] = useState<ReadingResult[]>(() => {
    const saved = localStorage.getItem('iching_history');
    return saved ? JSON.parse(saved) : [];
  });
  const [showHistory, setShowHistory] = useState(false);

  // Methods
  const handleStart = () => {
    if (!question.trim()) {
      alert("Please meditate on a question first.");
      return;
    }
    setStage('casting');
    setLines([]);
    setReadingResult(null);
  };

  const handleToss = () => {
    if (isCasting || lines.length >= 6) return;

    setIsCasting(true);
    // Logic happens in CoinAnimation callback
  };

  const onTossComplete = () => {
    setIsCasting(false);
    const newLine = tossCoins();
    const newLines = [...lines, newLine];
    setLines(newLines);

    if (newLines.length === 6) {
      finishReading(newLines);
    }
  };

  const finishReading = async (completedLines: CastLine[]) => {
    const { original, transformed } = getHexagramFromLines(completedLines);

    const result: ReadingResult = {
      lines: completedLines,
      originalHexagram: original,
      transformedHexagram: transformed,
      timestamp: Date.now(),
      question,
    };

    setReadingResult(result);
    setStage('result');
    setIsLoadingAI(true);

    // Fetch AI Interpretation
    const interpretation = await getInterpretation(question, completedLines, original, transformed);

    const finalResult = { ...result, aiInterpretation: interpretation };
    setReadingResult(finalResult);
    setIsLoadingAI(false);

    // Save to history
    const updatedHistory = [finalResult, ...history];
    setHistory(updatedHistory);
    localStorage.setItem('iching_history', JSON.stringify(updatedHistory));
  };

  const loadFromHistory = (reading: ReadingResult) => {
    setQuestion(reading.question);
    setLines(reading.lines);
    setReadingResult(reading);
    setStage('result');
    setShowHistory(false);
  };

  const reset = () => {
    setQuestion('');
    setLines([]);
    setStage('input');
    setReadingResult(null);
  };

  return (
    <div className="min-h-screen bg-slate-900 text-slate-200 font-sans selection:bg-amber-900 selection:text-white flex flex-col">

      {/* Header */}
      <header className="p-6 border-b border-slate-800 flex justify-between items-center bg-slate-900/90 sticky top-0 z-30 backdrop-blur-md">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 rounded-full border-2 border-amber-500 bg-amber-900 flex items-center justify-center font-serif font-bold text-amber-500">
            I
          </div>
          <h1 className="text-2xl font-serif text-amber-100 tracking-wide">Oracle AI</h1>
        </div>
        <button 
          onClick={() => setShowHistory(true)}
          className="px-4 py-2 text-sm text-slate-400 hover:text-amber-500 transition-colors"
        >
          History
        </button>
      </header>

      {/* Main Content */}
      <main className="flex-grow flex flex-col items-center justify-center p-4 max-w-4xl mx-auto w-full">

        {/* Stage 1: Input Question */}
        {stage === 'input' && (
          <div className="w-full max-w-lg animate-fade-in-up">
            <div className="text-center mb-10">
              <h2 className="text-4xl font-serif text-amber-50 mb-4">Consult the Oracle</h2>
              <p className="text-slate-400">Focus on a specific question or situation. Clear your mind.</p>
            </div>

            <div className="bg-slate-800 p-1 rounded-lg shadow-lg border border-slate-700 focus-within:border-amber-500 transition-colors">
              <textarea
                value={question}
                onChange={(e) => setQuestion(e.target.value)}
                placeholder="What is the wisdom for my current career path?..."
                className="w-full bg-slate-900 p-4 rounded text-lg outline-none min-h-[120px] text-slate-200 placeholder-slate-600 resize-none"
              />
            </div>

            <button
              onClick={handleStart}
              className="mt-8 w-full py-4 bg-gradient-to-r from-amber-700 to-amber-600 hover:from-amber-600 hover:to-amber-500 text-amber-50 font-serif font-bold text-lg rounded shadow-[0_0_20px_rgba(180,83,9,0.3)] transition-all transform hover:scale-[1.01]"
            >
              Begin Casting
            </button>
          </div>
        )}

        {/* Stage 2: Casting Lines */}
        {stage === 'casting' && (
          <div className="w-full flex flex-col items-center animate-fade-in">
            <h2 className="text-2xl font-serif text-slate-300 mb-2">Casting Line {lines.length + 1} of 6</h2>
            <p className="text-slate-500 text-sm mb-8 italic">"{question}"</p>

            <div className="flex gap-12 items-end mb-12">
               {/* Current Hexagram Building */}
               <HexagramDisplay lines={lines} highlightMoving={true} />
            </div>

            <div className="h-32 flex items-center justify-center mb-8">
               <CoinAnimation isTossing={isCasting} onTossComplete={onTossComplete} />
            </div>

            <button
              onClick={handleToss}
              disabled={isCasting}
              className={`px-12 py-4 rounded-full font-serif text-xl transition-all shadow-lg ${isCasting 
                ? 'bg-slate-700 text-slate-500 cursor-not-allowed' 
                : 'bg-amber-600 hover:bg-amber-500 text-white shadow-amber-900/50 hover:shadow-amber-600/50 hover:-translate-y-1'}`}
            >
              {isCasting ? 'Casting...' : 'Toss Coins'}
            </button>
            <p className="mt-6 text-slate-600 text-sm">Click to toss the three coins.</p>
          </div>
        )}

        {/* Stage 3: Result & Interpretation */}
        {stage === 'result' && readingResult && (
          <div className="w-full animate-fade-in pb-20">
            <button onClick={reset} className="mb-6 text-sm text-amber-500 hover:text-amber-300 flex items-center gap-1">
              ← New Reading
            </button>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">

              {/* Left Column: Hexagrams */}
              <div className="md:col-span-1 space-y-8">
                {/* Primary Hexagram */}
                <div className="bg-slate-800/50 p-6 rounded border border-slate-700">
                   <h3 className="text-center font-serif text-amber-500 text-lg mb-4">Primary Hexagram</h3>
                   <div className="flex justify-center mb-4">
                     <HexagramDisplay lines={readingResult.lines} highlightMoving={true} />
                   </div>
                   <div className="text-center">
                     <div className="text-4xl font-serif mb-1">{readingResult.originalHexagram.character}</div>
                     <div className="text-xl font-bold text-slate-200">{readingResult.originalHexagram.number}. {reading.originalHexagram.name}</div>
                     <div className="text-amber-200/80">{readingResult.originalHexagram.english}</div>
                   </div>
                </div>

                {/* Transformed Hexagram (if any) */}
                {readingResult.transformedHexagram && (
                  <div className="bg-slate-800/50 p-6 rounded border border-slate-700 relative overflow-hidden">
                     <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-amber-500 to-transparent opacity-50"></div>
                     <h3 className="text-center font-serif text-purple-400 text-lg mb-4">Relating Hexagram</h3>
                     <div className="flex justify-center mb-4">
                        {/* We need to reconstruct lines for display of transformed hexagram. 
                            Since we only have HexagramData, we can't easily rebuild the lines simply. 
                            However, purely for visual, we might just want to show the symbol or name. 
                            Actually, HexagramDisplay takes 'CastLine[]'.
                            Let's skip visual lines for transformed to keep it simple, or we'd need to reverse-engineer lines from binary.
                         */}
                        <div className="text-6xl text-slate-600 font-serif">→</div>
                     </div>
                     <div className="text-center">
                        <div className="text-4xl font-serif mb-1">{readingResult.transformedHexagram.character}</div>
                        <div className="text-xl font-bold text-slate-200">{readingResult.transformedHexagram.number}. {reading.transformedHexagram.name}</div>
                        <div className="text-purple-300/80">{readingResult.transformedHexagram.english}</div>
                     </div>
                  </div>
                )}
              </div>

              {/* Right Column: Interpretation */}
              <div className="md:col-span-2">
                <div className="bg-slate-800 p-8 rounded-lg shadow-xl border border-slate-700">
                  <h2 className="text-sm uppercase tracking-widest text-slate-500 mb-2">The Question</h2>
                  <p className="text-xl font-serif text-white italic mb-8 border-l-4 border-amber-600 pl-4 py-2 bg-slate-900/50">
                    "{readingResult.question}"
                  </p>

                  <h2 className="text-sm uppercase tracking-widest text-slate-500 mb-4">Interpretation</h2>

                  {isLoadingAI ? (
                    <div className="space-y-4 animate-pulse">
                      <div className="h-4 bg-slate-700 rounded w-3/4"></div>
                      <div className="h-4 bg-slate-700 rounded w-full"></div>
                      <div className="h-4 bg-slate-700 rounded w-5/6"></div>
                      <div className="mt-8 h-4 bg-slate-700 rounded w-1/2"></div>
                      <p className="text-amber-500/80 text-sm mt-4">Consulting the digital sage...</p>
                    </div>
                  ) : (
                    <div 
                      className="prose prose-invert prose-amber max-w-none text-slate-300 leading-relaxed"
                      dangerouslySetInnerHTML={{ 
                        // Basic markdown parsing for bold/headers/lines
                        __html: (readingResult.aiInterpretation || '')
                          .replace(/\*\*(.*?)\*\*/g, '<strong class="text-amber-100">$1</strong>')
                          .replace(/\n/g, '<br />')
                          .replace(/# (.*)/g, '<h3 class="text-xl font-serif text-amber-500 mt-6 mb-2">$1</h3>')
                      }} 
                    />
                  )}
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      <HistorySidebar 
        history={history} 
        onSelect={loadFromHistory} 
        isOpen={showHistory} 
        onClose={() => setShowHistory(false)} 
      />

      {/* Footer */}
      <footer className="p-4 text-center text-slate-600 text-xs border-t border-slate-800">
        <p>Oracle AI • I Ching • Powered by Gemini</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useEffect, useState } from 'react';

interface CoinAnimationProps {
  onTossComplete: () => void;
  isTossing: boolean;
}

const CoinAnimation: React.FC<CoinAnimationProps> = ({ onTossComplete, isTossing }) => {
  const [showResult, setShowResult] = useState(false);

  useEffect(() => {
    let timer: ReturnType<typeof setTimeout>;
    if (isTossing) {
      setShowResult(false);
      // Simulate animation duration
      timer = setTimeout(() => {
        setShowResult(true);
        // Small delay to show result before callback
        setTimeout(onTossComplete, 500); 
      }, 1500);
    }
    return () => clearTimeout(timer);
  }, [isTossing, onTossComplete]);

  if (!isTossing && !showResult) return null;

  return (
    <div className="flex justify-center gap-8 my-8 perspective-500">
      {[1, 2, 3].map((i) => (
        <div key={i} className={`relative w-16 h-16 rounded-full border-4 border-amber-500 bg-amber-200 shadow-[0_0_15px_rgba(245,158,11,0.5)] flex items-center justify-center text-amber-900 font-bold text-xl ${isTossing ? 'animate-[spin_0.5s_ease-in-out_infinite]' : ''}`}>
           <span className="opacity-80">
             {/* Simple visual representation */}
             {isTossing ? '?' : ((Math.random() > 0.5) ? 'Yin' : 'Yang')}
           </span>
        </div>
      ))}
      <style>{`
        .perspective-500 { perspective: 500px; }
      `}</style>
    </div>
  );
};

