import { GoogleGenAI } from "@google/genai";
import { CastLine, HexagramData } from '../types';
import { getChangingLinesIndices } from '../utils/ichingLogic';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getInterpretation = async (
  question: string,
  lines: CastLine[],
  original: HexagramData,
  transformed?: HexagramData
): Promise<string> => {

  const changingLines = getChangingLinesIndices(lines);

  let prompt = `You are an I Ching master sage. The user has asked the following question: "${question}".\n\n`;

  prompt += `The cast resulted in Hexagram ${original.number}: ${original.name} (${original.english}).\n`;
  prompt += `Character: ${original.character}\n`;
  prompt += `Key attributes: ${original.description}\n\n`;

  if (changingLines.length > 0) {
    prompt += `There are changing lines at positions: ${changingLines.join(', ')}.\n`;
    if (transformed) {
        prompt += `The hexagram transforms into Hexagram ${transformed.number}: ${transformed.name} (${transformed.english}).\n`;
        prompt += `Transformed attributes: ${transformed.description}\n`;
    }
  } else {
    prompt += `There are no changing lines. This indicates a static situation.\n`;
  }

  prompt += `\nPlease provide a profound, wisdom-filled, yet practical interpretation for the user. Structure the response in markdown with the following sections:\n`;
  prompt += `1. **The Core Situation**: What the primary hexagram says about their question.\n`;

  if (changingLines.length > 0) {
    prompt += `2. **The Changing Lines**:\n`;
    prompt += `   For each changing line (e.g. "Six in the third place"), provide a distinct paragraph that covers:\n`;
    prompt += `   - The traditional image or meaning of the line.\n`;
    prompt += `   - Specific advice for the user based on this line's position and nature.\n`;
    prompt += `   - How this line contributes to the change into the relating hexagram.\n`;
    prompt += `3. **The Outcome**: What the transformed hexagram implies for the future evolution of the situation.\n`;
  } else {
    prompt += `2. **Static Reading**: Explain the significance of receiving this hexagram without moving lines (a locked situation, or one requiring focus on the core attributes).\n`;
  }

  prompt += `4. **Sage's Advice**: A concise, actionable summary.\n\n`;
  prompt += `Tone: Mystical, calm, empathetic, and insightful. Avoid overly generic horoscope-style writing.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        temperature: 0.7,
      }
    });

    return response.text || "The oracle is silent at this moment. Please reflect on your question and try again.";
  } catch (error) {
    console.error("Error fetching interpretation:", error);
    return "The connection to the ethereal realm is disrupted. Please check your network and try again.";
  }
};

